def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        def complex_poly(val, degree):
            result = 0
            for d in range(1, degree + 1):
                result += ((-1) ** d) * (val ** d) / (d * 2.3)
            return result
        if ratio > 7:
            for a in range(1, 5):
                for b in range(3, 8):
                    term = (ratio - a) ** 4 / (b + 0.7) * np.sin(ratio * b / (a + 1))
                    priority += np.tanh(term) * (a + b) * 0.9
            exponent = np.exp(ratio / 3)
            priority += exponent * np.cos(ratio * 2.1) ** 2 + np.log(ratio + 1) * 5
        elif 5 < ratio <= 7:
            s = 0
            for x in range(1, 15):
                s += ((ratio - 5) ** x) / (x * 1.4) * np.cos(x * ratio * 1.7)
            priority = s + np.tanh(ratio - 6) * 12 - np.sqrt(ratio) * 3
            for y in range(1, 5):
                priority += np.sin(y * ratio) / (y + 0.5)
        elif 2 <= ratio <= 5:
            s = 0
            for p in range(1, 20):
                s += np.exp(-p / 20) * ((ratio - 2) ** p) / (p + 2) * np.cos(p * ratio)
            priority = s * np.cos(5 * ratio) - np.log(ratio + 0.5) * 7 + np.tanh(3 * (5 - ratio)) * 2
            if bin_cap < item * 2.2:
                priority += np.log1p(item / (bin_cap + 0.1)) * 3.5
            else:
                priority -= np.exp(-ratio / 2) * 2
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 25):
                s += ((2 - ratio) ** n) / (n ** 1.5) * np.sin(n * ratio * 2)
            priority = s + np.exp(-ratio) * 6
            penalty = 0
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(15 * ratio) * 3
            priority += penalty
            for m in range(1, 6):
                priority += np.sin(m * ratio * i) * ((ratio - 1) ** m) / (m + 0.7)
        elif 0.5 <= ratio < 1:
            s = 0
            for j in range(1, 20):
                s += ((1 - ratio) ** j) / (j * 3.7) * np.cos(j * item * 1.4)
            priority = s
            if (i * int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 2) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2.2) + 1.9)
            for k in range(1, 8):
                priority += ((1 - ratio) ** k) * np.sin(k * item * 1.5) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for l in range(1, 18):
                s += ((0.5 - ratio) ** l) / (l * 3) * np.cos(l * ratio * 1.8)
            priority = s + 1 / (bin_cap + 2)
            if int(item * 1.5) % 6 == 0:
                priority *= 2.7
            else:
                priority /= 2.8
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap) * 3.8
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 4) * np.sin(t * item * 1.0)
            priority = s + 2.3 / (bin_cap + 3.5)
            if int(item * 0.6) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.3
            if bin_cap < item * 0.18:
                priority += np.log1p(item * bin_cap) * 5.2
            else:
                priority -= np.exp(-ratio * 2.2) * 4.7
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 6) * np.cos(item * u * 0.85)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2.4 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-2.8 * ratio) * 4.5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priority += complex_poly(ratio * i * 0.8, 8)
        priorities[i] = priority
    return priorities
